var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"도, 도시가 사라졌어.","JPN":"と、都市が消えた。","ENG":"Th-the city disappeared.","TWN":"城，城市消失了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"……그 침식체를 어떻게든 막아낸 건가.","JPN":"……あの侵食体をなんとか追い払ったのか。","ENG":"...Did she really stop that C.O. somehow?","TWN":"……總算是擋下了那個侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"압도적인 차이였다.","JPN":"圧倒的な力だった。","ENG":"It was overwhelming power.","TWN":"實力差距太大了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"저 여자가 없었다면…… 우린 분명 살아남지 못했겠지.","JPN":"あの女がいなければ……俺たちは間違いなく全滅だった。","ENG":"If it weren't for her... we wouldn't be alive right now.","TWN":"如果沒有那個女人……我們肯定沒辦法活的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합! 아합은 어디있지?","JPN":"アハブ！　アハブはどこにいる？","ENG":"Ahab! Where are you?","TWN":"亞哈！亞哈在哪？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"에스타크의 포격이 통하지 않은 걸 보고 바로 도망친 것 같다.","JPN":"エスタークの砲撃が効かないとわかった途端、逃げやがったらしい。","ENG":"I think he fled after seeing that the Estaque's bombardment didn't work.","TWN":"他看到艾斯塔克沒效，就立刻逃跑了吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"망할 새끼. 그렇게 자신만만해하더니.","JPN":"クソ野郎。あんな自信満々だったくせに。","ENG":"That bastard. I should've known when he looked too confident.","TWN":"混帳東西，之前還一副胸有成竹的樣子。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"제대로 당했어.","JPN":"コテンパンにやられたな。","ENG":"He tricked us.","TWN":"被他給擺了一道。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"로터스에선 아무도 믿으면 안 되는 법인데, 젠장.","JPN":"ロータスでは誰も信じるなということを忘れていたぜ、くそぉ。","ENG":"You can't trust anyone in Lotus, crap.","TWN":"該死的，在洛德斯果然不該相信任何人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"이, 이봐. 미안하게 됐어. 우리도 일이 이렇게 될 줄은 몰랐다고.","JPN":"お、おい、すまなかった。俺たちだって、まさかこうなるとは思わなかった。","ENG":"H-hey. Sorry about all this. We didn't know either that it'd turn out this way.","TWN":"那個，很抱歉，我們也沒想到事情會變成這樣。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"저런 침식체는 처음 봤단 말이야.","JPN":"あんな侵食体は見たこともなかったんだ。","ENG":"It's my first time seeing a C.O. like that.","TWN":"我還是第一次見到那種侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"당신 같이 강한 카운터도 어쩌지 못하는 걸 우리가 할 수는 없으니까…….","JPN":"あんたのような強いカウンターでもどうにもならない相手に、俺たちが敵うわけないからな……","ENG":"And there's nothing we can do when a strong Counter like you can't either...","TWN":"像連你這麼強的制裁者都無能為力，更別說我們……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……알고 있었다. 너희의 힘으로는 어림도 없다는 걸.","JPN":"……わかっている。君たちじゃどうにもならないってことは。","ENG":"...I knew that it was beyond your capabilities.","TWN":"……我早就知道，以你們的能力是不可能成功的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"결국 이번에도 놈을 죽이지 못했어.","JPN":"結局、今回も奴を殺せなかった。","ENG":"In the end, I wasn't able to kill it this time.","TWN":"結果這次也沒能殺掉那傢伙。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합은 침식체가 날 찾아올 거란 걸 알고 있었나?","JPN":"そもそもアハブは、私が侵食体を惹き付けるだろうと最初から想定していた？","ENG":"Did Ahab know that the C.O. would come after me?","TWN":"亞哈知道侵蝕體會衝著我來嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇기에 에스타크의 위력을 잘 알고 있는 나에게 의도적으로 접근한 걸지도.","JPN":"エスタークの威力をよく知っている私に近づいたのも、意図的なものだったのかもしれない。","ENG":"Perhaps that's why he deliberately approached me, who knew Estaque's firepower from the start.","TWN":"而且知道我熟悉艾斯塔克的威力，就用這一點來刻意接近我。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇다면…… 아합은 나에 대해 알고 있던 것일까?","JPN":"つまり……アハブは私のことを以前から知っていた？","ENG":"Then... does that mean he knows something about me?","TWN":"這表示……他知道關於我的事？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"서로의 욕심이 화를 부른 거다. 나도, 너희들도. 그 아합이란 자의 꼬임에 휘둘려서.","JPN":"今回の失態は我々の身から出たさびだ。お互いの欲を、あのアハブという者の思惑に利用れてしまった。","ENG":"Our greed is what caused this disaster. You and I were fooled by Ahab.","TWN":"是我們的私慾引來的災禍。不僅是我，還有你們，都掉入亞哈設下的局裡。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러니…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우, 우리가 그 새끼를 찾아볼게!","JPN":"お、俺たちが奴を捜索してみるよ！","ENG":"W-we'll go look for that bastard!","TWN":"我，我們會找到那個臭傢伙的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그 아합이란 새끼도 분명 사막을 뒤지면 흔적이라도 나올 거야!","JPN":"アハブだって、砂漠をくまなく探せば、痕跡ぐらい残しているはずさ！","ENG":"I'm sure if we search the desert, we'll find traces of him!","TWN":"就算要翻遍這座沙漠也會把他找出來的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그 고래 같은 녀석도 어떻게든 처리할게!","JPN":"あのクジラみたいな奴も、なんとかしてみるぜ！","ENG":"We'll also deal with that whale somehow!","TWN":"還，還有那隻鯨魚我們也會想辦法處理的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"혼자 움직이는 것보다는 여럿이서 움직이는 게 낫잖아? 안 그래?","JPN":"一人より、集団で動いた方がいいだろう？　なぁ？","ENG":"Won't it be better to move as a group than alone?","TWN":"俗話說團結力量大，你說對吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우리 애들 풀어서 뒤지다 보면 하다못해 양말 한 짝이라도 찾을 수 있을 거라고!","JPN":"うちの連中に探させれば、何かしらは見つけられるはずさ！","ENG":"If we spread ourselves and search for him, I'm sure we'll find where he's been! Or at least a pair of his socks!","TWN":"叫手下們出去找，再怎麼樣也會找到一隻襪子吧！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그, 그러니까 죽이진 말아줘! 여기선 네가 제일 강하니까, 하라는 대로 할게!","JPN":"だから、殺さないでくれ！　ここじゃお前が一番強いから、お前に従うよ！","ENG":"S-so, please don't kill us! Since you're the strongest out of us, we'll do as you say!","TWN":"所，所以，拜託不要殺我！現在你是我們當中最強的，我什麼都聽你的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"아합이라는 자는 우릴 배신했다. 그리고 침식체의 먹이가 될 뻔했어.","JPN":"アバブという奴は俺たちを裏切った。そして侵食体の餌にされるところだった。","ENG":"Ahab betrayed us. And we almost became prey to a C.O. as a result.","TWN":"亞哈那傢伙背叛我們，還害我們差點變成侵蝕體的食物。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"원수는 4배로, 은혜는 2배로 갚는 게 우리 딱정벌레의 규칙.","JPN":"報復は4倍返し、恩返しは2倍返しというのが、俺たちカブトムシの掟。","ENG":"It's the Beetles' way that we repay enemies fourfold and favors twofold.","TWN":"報仇要四倍奉還，報恩也要兩倍奉還，這是我們甲蟲幫的規矩。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"그러니 딱정벌레는 당신을 돕겠다. 이 자리에서 죽으라는 말만 아니라면 뭐든지 하겠어.","JPN":"従って、カブトムシはお前を支援する。ここで自決しろってこと以外なら、どんな命令でも聞くぞ。","ENG":"So, we will help you. We will do as you command, as long as it's not an order to die right now.","TWN":"我們甲蟲幫也會助你一臂之力，只要別讓我死在這裡，我什麼都願意做。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"아합을 찾아보겠다. 그리고…… 침식체는 우리 장비로 역부족이라는 걸 인정하지.","JPN":"アハブを探し出そう。あと……侵食体に俺たちの装備は通用しないってことも認める。","ENG":"We'll look for Ahab. And... I admit that our gear is not enough to fight that C.O.","TWN":"我們也會去找亞哈。還有……我承認以我們的裝備打不過那個侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"……마음에는 안 들지만 관리국에도 지원을 요청하겠다.","JPN":"……あまり気は進まないが、管理局に支援要請も出しておく。","ENG":"...I don't want to do this, but I'll also request support from the Administration.","TWN":"……雖然千百個不願意，但我們還是會向管理局請求支援的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……사상자를 수습하고 도시로 돌아가라.","JPN":"……死傷者を連れて、街に戻れ。","ENG":"...Pick up the casualties and head back to the city.","TWN":"……你們帶傷者一起回去吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너희가 뭘 하고 다니는 녀석들인지는 몰라도, 사람의 목숨은 이렇게 희생해선 안 돼.","JPN":"君たちがどんな連中かは知らないが、命を浪費させるわけにはいかない。","ENG":"I don't know what you all have been doing until now, but we mustn't let people's lives be sacrificed like this.","TWN":"不管你們是什麼樣的人，人的性命都不應該這樣被犧牲。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"고래를 토벌해야 한다는 것에는 동의한다. 믿을만한 곳에 지원을 요청하도록.","JPN":"クジラを討伐すべきということについては同感だ。信頼できるところに支援を仰ぐといい。","ENG":"I agree with you that the whale must be exterminated. Request support from whomever you trust.","TWN":"討伐鯨魚的部分我也同意，請尋求可靠的支援。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나는 어떻게든 침식체를 찾아내고, 기회를 노려보겠다.","JPN":"私はなんとしてでも侵食体を探し出し、反撃のチャンスをうかがうとする。","ENG":"I will try to find the C.O. and wait for my chance.","TWN":"無論如何我會找到侵蝕體，伺機而動。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너희가 관리국의 지원을 받는 데 성공하면 곧장 달려오길 기대하지.","JPN":"君たちが管理局の支援を受け、すぐにでも追いかけて来てくれることを願おう。","ENG":"Also, I expect that you will all come back if you succeed in receiving the Administration's support.","TWN":"如果你們能成功取得管理局的支援，希望你們能立刻趕來。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"지키지 못했다는 생각은 머릿속을 난도질한다.","JPN":"守ることができなかった、という事実が私を責め続ける。","ENG":"The thought that I couldn't protect them wreaked havoc in my head.","TWN":"我沒能保護大家，這個念頭一直在我腦海中揮之不去。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"침식체가 보여준 환상 속에서 고통스럽게 죽어가던 그들은, 내 동료였을까?","JPN":"侵食体に見せられた幻覚の中にいた、苦しみながら死んでいった者たちは、私の仲間だったのだろうか？","ENG":"The hallucinations the C.O. showed me of people dying horrible deaths... Were they my comrades?","TWN":"侵蝕體讓我看到的幻覺中，那些在痛苦死去的人是我的同伴嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"눈을 감으면 들려오는 총성. 사람들의 비명소리. 죽어가던 동료들.","JPN":"目を閉じる度に聞こえてくる銃声、人の叫び声、死にゆく仲間たち。","ENG":"When I close my eyes, I hear gunshots and people screaming. Also, comrades dying.","TWN":"閉上眼睛就能聽到槍聲，人們的尖叫聲，垂死的同伴們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그들의 얼굴, 목소리, 이름. 그 어떤것도 떠오르지 않아.","JPN":"彼らの顔、声、名前、何一つ思い出せない。","ENG":"But I can't recall any of their faces, voices, or names.","TWN":"他們的臉、聲音、名字，什麼都想不起來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"나는 너희에게 어떤 존재였지?","JPN":"私は、君たちにとって何だったのか？","ENG":"Who was I to them?","TWN":"我對你們來說，到底是什麼樣的存在？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그림자는 여전히 내가 필요하다고 말했어.","JPN":"シャドウは、今でも私が必要だと言っていた。","ENG":"The Shadow said that she still needed me.","TWN":"那個暗影說需要我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"그 소녀도…… 내가 지키지 못한 동료였던 걸까?","JPN":"あの少女も……私が守れなかった仲間の一人だったんだろうか？","ENG":"Was the girl also... a comrade that I couldn't save?","TWN":"她也曾是……我沒能保護的同伴嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"환상 속에서 날 원망하던 동료들도…… 결국 나로 인해서…….","JPN":"幻覚の中にいた、私を恨んでいた者たちも……やはり私のせいで……","ENG":"The comrades who resented me in these visions... all because of me...","TWN":"在幻象中責備我的同伴們……是因為我才落得如此下場……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"아샤. 결국 그녀의 시체조차 찾지 못했다","JPN":"アーシャ。結局彼女の遺体を見つけることはできなかった。","ENG":"Asha. I couldn't even find her corpse.","TWN":"還有阿莎，最終連她的遺體都沒找到"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"그저 사라진 아버지를 찾고 싶은 작은 소망조차 내가 망쳐버린 거야.","JPN":"お父さんを見つけ出したいという小さな望みも、私が妨げてしまったんだ。","ENG":"I ruined her hope of wanting to find her missing father.","TWN":"就連想要找到失蹤的爸爸這麼小的心願，也被我搞砸了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"나 때문에…… 나 때문에 아샤가…….","JPN":"私のせいで……私のせいでアーシャが……","ENG":"Because of me... Asha is...","TWN":"都是因為我……因為我，阿莎才會……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"결국 아무것도 지켜내지 못했어.","JPN":"結局、何も守れなかった。","ENG":"I couldn't protect anything.","TWN":"結果我什麼也保護不了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"동료도 기억도, 내가 지켜내야 할 사람도…… 모두.","JPN":"仲間も、記憶も、守るべき存在も……何もかも。","ENG":"My comrades, my memories, not even the people I needed to protect... Nothing.","TWN":"同伴也好，記憶也好，我要守護的人也好……所有的一切。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나에게 남은 건 결국…….","JPN":"私に残されたのは結局……","ENG":"The only thing that remains for me is...","TWN":"最後留給我的……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아무것도 남지 않은 빈껍데기뿐이로군.","JPN":"何も残っていない、抜け殻だけだな。","ENG":"Just an empty shell.","TWN":"只剩下一具空殼。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};